mapper.select:
select
	t1.id                             ,
	t1.created_by                     ,
	t1.last_updated_by                ,
	t1.work_tasks                     ,
	t1.person_liable                  ,
	t1.fk_sub_col_id                  ,
	t1.creation_date                  ,
	t1.is_completion                  ,
	t1.last_update_date               ,
	t1.top_date_evolve                ,
	t1.completion_node                ,
	t1.is_keyno                       ,
	t1.date_evolve                    ,
	t1.version                        ,
	t1.created_dept                   ,
	t1.org_identity                   ,
	t1.work_class                     ,
	t1.last_update_ip                 ,
	t1.dept_id                        ,
	t1.content                        
from weekly 	t1


			and t1.ID =#{id}


			and t1.CREATED_BY =#{createdBy}


			and t1.LAST_UPDATED_BY =#{lastUpdatedBy}


			and t1.WORK_TASKS =#{workTasks}


			and t1.PERSON_LIABLE =#{personLiable}


			and t1.FK_SUB_COL_ID =#{fkSubColId}


			and t1.CREATION_DATE =#{creationDate}


			and t1.IS_COMPLETION =#{isCompletion}


			and t1.LAST_UPDATE_DATE =#{lastUpdateDate}


			and t1.TOP_DATE_EVOLVE =#{topDateEvolve}


			and t1.COMPLETION_NODE >= #{completionNodeBegin}


			and t1.COMPLETION_NODE <= #{completionNodeEnd}


			and t1.IS_KEYNO =#{isKeyno}


			and t1.DATE_EVOLVE =#{dateEvolve}


			and t1.VERSION =#{version}


			and t1.CREATED_DEPT =#{createdDept}


			and t1.ORG_IDENTITY =#{orgIdentity}


			and t1.WORK_CLASS =#{workClass}


			and t1.LAST_UPDATE_IP =#{lastUpdateIp}


			and t1.CONTENT =#{content}

	SELECT 
distinct
	t1.rolling_plandate ,
	t1.rolling_plan_date, t1.rolling_plan_content,t1.rolling_plan_assignment,t1.rolling_plan_target
FROM
	rolling_plan t1


				and t1.ID =#{id}


				and t1.CREATED_BY =#{createdBy}


				and t1.LAST_UPDATED_BY =#{lastUpdatedBy}


				and t1.FK_SUB_COL_ID =#{fkSubColId}


				and t1.CREATION_DATE =#{creationDate}


				and t1.ROLLING_PLAN_CONTENT =#{rollingPlanContent}


				and t1.LAST_UPDATE_DATE =#{lastUpdateDate}


				and t1.ROLLING_PLAN_ASSIGNMENT =#{rollingPlanAssignment}


				and t1.ROLLING_PLAN_DATE >= #{rollingPlanDateBegin}


				and t1.ROLLING_PLAN_DATE <= #{rollingPlanDateEnd}


				and t1.ROLLING_PLAN_TARGET =#{rollingPlanTarget}


				and t1.VERSION =#{version}


				and t1.CREATED_DEPT =#{createdDept}


				and t1.ORG_IDENTITY =#{orgIdentity}


				and t1.LAST_UPDATE_IP =#{lastUpdateIp}


				and t1.DEPT_ID =#{deptId}


				and t1.ROLLING_PLANDATE =#{rollingPlandate}


select * from  rolling_plan	 where fk_SUB_COL_ID = (
  select id from( select id from dyn_meekly  where is_son='1'   order by creation_date desc) where rownum = 1

     )
